+/// Debug log file for CDP interactions
+var debug_log_file: ?std.fs.File = null;
+
+pub fn initDebugLog() void {
+    debug_log_file = std.fs.cwd().createFile("/tmp/termweb-mouse.log", .{ .truncate = true }) catch null;
