+
+pub fn deinitDebugLog() void {
+    if (debug_log_file) |f| {
+        f.close();
+        debug_log_file = null;
+    }
+}
+
+fn debugLog(comptime fmt: []const u8, args: anytype) void {
+    if (debug_log_file) |f| {
+        var buf: [1024]u8 = undefined;
+        const msg = std.fmt.bufPrint(&buf, fmt, args) catch return;
+        f.writeAll(msg) catch {};
+        f.sync() catch {};
+    }
+}
